from haystack import component
from haystack.dataclasses import ChatMessage
from typing import Dict, Any

@component
class SessionMemoryStore:
    @component.output_types(retrieved_history=list[ChatMessage])
    def run(self, session_id: str, query: str) -> Dict[str, Any]:
        if not hasattr(self, 'sessions'):
            self.sessions = {}

        if session_id not in self.sessions:
            self.sessions[session_id] = []

        # Retrieve relevant history
        history = self.sessions[session_id][-5:]  # Last 5 exchanges
        relevant_history = [msg for msg in history if 'memory' in msg.content.lower() or 'haystack' in msg.content.lower()]

        return {'retrieved_history': relevant_history}

    @component
    def save(self, session_id: str, messages: list[ChatMessage]):
        self.sessions[session_id].extend(messages[-2:])  # Save last exchange
